mapper.update:
UPDATE ${table}
SET status = #{status}, updated_at = NOW()
WHERE order_no = #{orderNo}

mapper.select:
SELECT id, order_no AS orderNo, user_id AS userId, total_amount AS totalAmount,
       pay_amount AS payAmount, status, created_at AS createdAt, updated_at AS updatedAt
FROM ${table}
WHERE order_no = #{orderNo}

SELECT id, order_no AS orderNo, product_id AS productId, product_name AS productName,
       store_id AS storeId, store_name AS storeName, product_image_url AS productImageUrl,
       product_description AS productDescription,
       unit_price AS unitPrice, quantity
FROM ${table}
WHERE order_no = #{orderNo}

SELECT id, order_no AS orderNo, user_id AS userId, total_amount AS totalAmount,
       pay_amount AS payAmount, status, created_at AS createdAt, updated_at AS updatedAt
FROM ${table}
WHERE status = 'WAIT_PAY' AND TIMESTAMPDIFF(MINUTE, created_at, NOW()) >= #{minutes}
LIMIT 100
